/**
 * Self-contained tests for spiderweb topology + projection shape/unit helpers.
 *
 * Run:
 *   pnpm run gnode -- run open-source/gnosis/src/__tests__/spiderweb-topology.test.ts
 */

import assert from 'node:assert';
import {
  analyzeProjectionPredictive,
  analyzeProjectionShapeUnit,
  dimensionalUnitGap,
  hasDimensionalUnitGap,
  isProjectionParadox,
  meshRoutingPaths,
  paradoxUnitSandwich,
  predictParadoxUnitLowerBoundFromFrame,
  projectionParadoxUnits,
  reducedObservedLatentRatio,
  scanReductionProjections,
} from '../spiderweb-topology';

// Canonical spiderweb routing paths.
assert.strictEqual(meshRoutingPaths({ peers: 7, hops: 3 }), 21);
assert.strictEqual(meshRoutingPaths({ peers: 11, hops: 5 }), 55);

// Dimensional unit gaps.
assert.strictEqual(dimensionalUnitGap({ observedDim: 2, latentDim: 3 }), 1);
assert.strictEqual(dimensionalUnitGap({ observedDim: 2, latentDim: 54 }), 52);
assert.strictEqual(hasDimensionalUnitGap({ observedDim: 2, latentDim: 54 }), true);
assert.strictEqual(hasDimensionalUnitGap({ observedDim: 54, latentDim: 2 }), false);

// Reduced observed:latent ratios.
assert.deepStrictEqual(reducedObservedLatentRatio({ observedDim: 2, latentDim: 3 }), [2, 3]);
assert.deepStrictEqual(reducedObservedLatentRatio({ observedDim: 2, latentDim: 54 }), [1, 27]);
assert.deepStrictEqual(reducedObservedLatentRatio({ observedDim: 0, latentDim: 0 }), [0, 0]);

// Frame-only predictor.
assert.strictEqual(predictParadoxUnitLowerBoundFromFrame({ observedDim: 2, latentDim: 3 }), 1);
assert.strictEqual(predictParadoxUnitLowerBoundFromFrame({ observedDim: 2, latentDim: 54 }), 1);
assert.strictEqual(predictParadoxUnitLowerBoundFromFrame({ observedDim: 54, latentDim: 2 }), 0);

// Projection paradox units.
const paradoxWitness = {
  observedHasSolution: false,
  latentHasSolution: true,
  hasCollapsedSplit: true,
} as const;
assert.strictEqual(isProjectionParadox(paradoxWitness), true);
assert.strictEqual(projectionParadoxUnits(paradoxWitness), 1);

const nonParadoxWitness = {
  observedHasSolution: true,
  latentHasSolution: true,
  hasCollapsedSplit: true,
} as const;
assert.strictEqual(isProjectionParadox(nonParadoxWitness), false);
assert.strictEqual(projectionParadoxUnits(nonParadoxWitness), 0);

// Sandwich + predictive diagnostics.
const sandwich = paradoxUnitSandwich(
  { observedDim: 2, latentDim: 54 },
  paradoxWitness
);
assert.strictEqual(sandwich.predictedLowerBound, 1);
assert.strictEqual(sandwich.observedUnits, 1);
assert.strictEqual(sandwich.dimensionalUpperBound, 52);
assert.strictEqual(sandwich.withinBounds, true);

const predictive = analyzeProjectionPredictive(
  { observedDim: 2, latentDim: 54 },
  paradoxWitness
);
assert.strictEqual(predictive.predictedLowerBound, 1);
assert.strictEqual(predictive.observedUnits, 1);
assert.strictEqual(predictive.residual, 0);
assert.strictEqual(predictive.consistent, true);

const report = analyzeProjectionShapeUnit(
  { observedDim: 2, latentDim: 54 },
  paradoxWitness
);
assert.strictEqual(report.dimensionalUnitGap, 52);
assert.deepStrictEqual(report.reducedObservedLatentRatio, [1, 27]);
assert.strictEqual(report.paradoxUnits, 1);
assert.strictEqual(report.hasShape, true);

// Cross-reduction scan.
const scans = scanReductionProjections([
  {
    id: 'clinamen',
    frame: { observedDim: 2, latentDim: 3 },
    witness: paradoxWitness,
  },
  {
    id: 'no-gap-control',
    frame: { observedDim: 3, latentDim: 3 },
    witness: nonParadoxWitness,
  },
]);
assert.strictEqual(scans.length, 2);
assert.strictEqual(scans[0].id, 'clinamen');
assert.strictEqual(scans[0].shapeUnit.paradoxUnits, 1);
assert.strictEqual(scans[0].sandwich.withinBounds, true);
assert.strictEqual(scans[0].predictive.consistent, true);
assert.strictEqual(scans[1].id, 'no-gap-control');
assert.strictEqual(scans[1].shapeUnit.paradoxUnits, 0);
assert.strictEqual(scans[1].sandwich.withinBounds, true);
assert.strictEqual(scans[1].predictive.consistent, true);

console.log('spiderweb-topology: all tests passed');
